package com.banking.secure.security;

import android.content.Context;
import android.os.SystemClock;

import java.io.IOException;
import java.security.GeneralSecurityException;
import java.security.SecureRandom;
import java.util.Base64;

public final class SessionManager {

    private static final String SESSION_TOKEN_KEY = "session_token";
    private static final String SESSION_EXPIRY_KEY = "session_expiry";
    private static final long SESSION_TIMEOUT_MS = 5 * 60 * 1000; // 5 minutes
    private static final int TOKEN_LENGTH = 32;

    private final SecureStorageManager storageManager;
    private long lastActivityTime;
    private volatile boolean isAuthenticated = false;

    public SessionManager(Context context) throws GeneralSecurityException, IOException {
        this.storageManager = SecureStorageManager.getInstance(context);
        this.lastActivityTime = SystemClock.elapsedRealtime();
    }

    public String createSession() {
        SecureRandom secureRandom = new SecureRandom();
        byte[] tokenBytes = new byte[TOKEN_LENGTH];
        secureRandom.nextBytes(tokenBytes);
        String token = android.util.Base64.encodeToString(tokenBytes, android.util.Base64.NO_WRAP);

        long expiry = System.currentTimeMillis() + SESSION_TIMEOUT_MS;
        storageManager.storeSecurely(SESSION_TOKEN_KEY, token);
        storageManager.storeSecurely(SESSION_EXPIRY_KEY, String.valueOf(expiry));

        lastActivityTime = SystemClock.elapsedRealtime();
        isAuthenticated = true;

        return token;
    }

    public boolean isSessionValid() {
        if (!isAuthenticated) {
            return false;
        }

        long elapsed = SystemClock.elapsedRealtime() - lastActivityTime;
        if (elapsed > SESSION_TIMEOUT_MS) {
            invalidateSession();
            return false;
        }

        String expiryStr = storageManager.retrieveSecurely(SESSION_EXPIRY_KEY);
        if (expiryStr == null) {
            invalidateSession();
            return false;
        }

        try {
            long expiry = Long.parseLong(expiryStr);
            if (System.currentTimeMillis() > expiry) {
                invalidateSession();
                return false;
            }
        } catch (NumberFormatException e) {
            invalidateSession();
            return false;
        }

        return true;
    }

    public void refreshSession() {
        if (isSessionValid()) {
            lastActivityTime = SystemClock.elapsedRealtime();
            long newExpiry = System.currentTimeMillis() + SESSION_TIMEOUT_MS;
            storageManager.storeSecurely(SESSION_EXPIRY_KEY, String.valueOf(newExpiry));
        }
    }

    public void invalidateSession() {
        isAuthenticated = false;
        storageManager.removeSecurely(SESSION_TOKEN_KEY);
        storageManager.removeSecurely(SESSION_EXPIRY_KEY);
    }

    public String getSessionToken() {
        if (!isSessionValid()) {
            return null;
        }
        return storageManager.retrieveSecurely(SESSION_TOKEN_KEY);
    }
}

