package com.banking.secure.security;

import java.math.BigDecimal;
import java.util.regex.Pattern;

public final class InputValidator {

    private static final Pattern ACCOUNT_ID_PATTERN = Pattern.compile("^[A-Za-z0-9]{8,20}$");
    private static final Pattern DESCRIPTION_PATTERN = Pattern.compile("^[A-Za-z0-9\\s.,\\-]{0,200}$");
    private static final BigDecimal MAX_TRANSACTION_AMOUNT = new BigDecimal("1000000.00");
    private static final BigDecimal MIN_TRANSACTION_AMOUNT = new BigDecimal("0.01");

    private InputValidator() {}

    public static boolean isValidAccountId(String accountId) {
        if (accountId == null || accountId.isEmpty()) {
            return false;
        }
        return ACCOUNT_ID_PATTERN.matcher(accountId).matches();
    }

    public static boolean isValidAmount(BigDecimal amount) {
        if (amount == null) {
            return false;
        }
        if (amount.scale() > 2) {
            return false;
        }
        return amount.compareTo(MIN_TRANSACTION_AMOUNT) >= 0
                && amount.compareTo(MAX_TRANSACTION_AMOUNT) <= 0;
    }

    public static boolean isValidDescription(String description) {
        if (description == null) {
            return true; // Description is optional
        }
        return DESCRIPTION_PATTERN.matcher(description).matches();
    }

    public static String sanitizeDescription(String input) {
        if (input == null) {
            return "";
        }
        // Remove any characters that aren't alphanumeric, spaces, periods, commas, or hyphens
        String sanitized = input.replaceAll("[^A-Za-z0-9\\s.,\\-]", "");
        // Truncate to max length
        if (sanitized.length() > 200) {
            sanitized = sanitized.substring(0, 200);
        }
        return sanitized;
    }
}

