import okhttp3.CertificatePinner;
import okhttp3.OkHttpClient;
import okhttp3.ConnectionSpec;
import okhttp3.TlsVersion;
import okhttp3.CipherSuite;

public final class SecureHttpClient {

    private static final String API_HOST = "api.securebank.example.com";

    // In production, these would be the actual SHA-256 hashes of your server's certificate pins
    private static final String PRIMARY_PIN = "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=";
    private static final String BACKUP_PIN = "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=";

    private static volatile OkHttpClient instance;

    private SecureHttpClient() {}

    public static OkHttpClient getInstance() {
        if (instance == null) {
            synchronized (SecureHttpClient.class) {
                if (instance == null) {
                    instance = createSecureClient();
                }
            }
        }
        return instance;
    }

    private static OkHttpClient createSecureClient() {
        CertificatePinner certificatePinner = new CertificatePinner.Builder()
                .add(API_HOST, PRIMARY_PIN)
                .add(API_HOST, BACKUP_PIN)
                .build();

        // Enforce modern TLS
        ConnectionSpec modernTls = new ConnectionSpec.Builder(ConnectionSpec.MODERN_TLS)
                .tlsVersions(TlsVersion.TLS_1_2, TlsVersion.TLS_1_3)
                .cipherSuites(
                        CipherSuite.TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256,
                        CipherSuite.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
                        CipherSuite.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
                        CipherSuite.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
                        CipherSuite.TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305_SHA256,
                        CipherSuite.TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305_SHA256
                )
                .build();

        return new OkHttpClient.Builder()
                .certificatePinner(certificatePinner)
                .connectionSpecs(Collections.singletonList(modernTls))
                .connectTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
                .readTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
                .writeTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
                .followRedirects(false)
                .followSslRedirects(false)
                .build();
    }
}

