package com.banking.secure.logging;

import android.util.Log;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;
import java.util.TimeZone;

public final class AuditLogger {

    private static final String TAG = "BankingAudit";

    public enum EventType {
        TRANSACTION_INITIATED,
        TRANSACTION_COMPLETED,
        TRANSACTION_FAILED,
        AUTHENTICATION_SUCCESS,
        AUTHENTICATION_FAILURE,
        SESSION_CREATED,
        SESSION_EXPIRED,
        SECURITY_VIOLATION,
        BALANCE_QUERIED
    }

    private AuditLogger() {}

    public static void log(EventType eventType, String message) {
        String timestamp = getTimestamp();
        // Never log sensitive data like account numbers, balances, or tokens
        String sanitizedMessage = sanitizeLogMessage(message);
        String logEntry = String.format("[%s] %s: %s", timestamp, eventType.name(), sanitizedMessage);

        switch (eventType) {
            case SECURITY_VIOLATION:
            case AUTHENTICATION_FAILURE:
                Log.w(TAG, logEntry);
                break;
            case TRANSACTION_FAILED:
                Log.e(TAG, logEntry);
                break;
            default:
                Log.i(TAG, logEntry);
                break;
        }

        // In production, send to secure remote logging service
        // sendToRemoteLogger(logEntry);
    }

    private static String getTimestamp() {
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'", Locale.US);
        sdf.setTimeZone(TimeZone.getTimeZone("UTC"));
        return sdf.format(new Date());
    }

    private static String sanitizeLogMessage(String message) {
        if (message == null) return "";
        // Remove potential sensitive data patterns
        String sanitized = message;
        // Mask account numbers (keep last 4)
        sanitized = sanitized.replaceAll("\\b\\d{8,20}\\b", "****");
        // Remove potential tokens
        sanitized = sanitized.replaceAll("(?i)(token|password|pin|secret)\\s*[:=]\\s*\\S+", "$1=***REDACTED***");
        return sanitized;
    }
}

