package com.banking.secure.security;

import android.content.Context;

import androidx.annotation.NonNull;
import androidx.biometric.BiometricManager;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;
import androidx.fragment.app.FragmentActivity;

import com.banking.secure.logging.AuditLogger;

import java.util.concurrent.Executor;

public final class BiometricAuthManager {

    public interface AuthCallback {
        void onAuthSuccess();
        void onAuthError(String error);
        void onAuthFailed();
    }

    private final FragmentActivity activity;

    public BiometricAuthManager(FragmentActivity activity) {
        this.activity = activity;
    }

    public boolean isBiometricAvailable() {
        BiometricManager biometricManager = BiometricManager.from(activity);
        int canAuthenticate = biometricManager.canAuthenticate(
                BiometricManager.Authenticators.BIOMETRIC_STRONG);
        return canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS;
    }

    public void authenticate(String title, String subtitle, AuthCallback callback) {
        if (!isBiometricAvailable()) {
            callback.onAuthError("Biometric authentication not available");
            return;
        }

        Executor executor = ContextCompat.getMainExecutor(activity);

        BiometricPrompt biometricPrompt = new BiometricPrompt(activity, executor,
                new BiometricPrompt.AuthenticationCallback() {
                    @Override
                    public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                        super.onAuthenticationSucceeded(result);
                        AuditLogger.log(AuditLogger.EventType.AUTHENTICATION_SUCCESS,
                                "Biometric authentication succeeded");
                        callback.onAuthSuccess();
                    }

                    @Override
                    public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                        super.onAuthenticationError(errorCode, errString);
                        AuditLogger.log(AuditLogger.EventType.AUTHENTICATION_FAILURE,
                                "Biometric authentication error");
                        callback.onAuthError(errString.toString());
                    }

                    @Override
                    public void onAuthenticationFailed() {
                        super.onAuthenticationFailed();
                        AuditLogger.log(AuditLogger.EventType.AUTHENTICATION_FAILURE,
                                "Biometric authentication failed");
                        callback.onAuthFailed();
                    }
                });

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle(title)
                .setSubtitle(subtitle)
                .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG)
                .setNegativeButtonText("Cancel")
                .setConfirmationRequired(true)
                .build();

        biometricPrompt.authenticate(promptInfo);
    }
}

